&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Prepare and process weekly accounts payable payment runs&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Monitor outstanding invoices and follow up on discrepancies&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Review employee expense claims, ensuring compliance and completeness&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Follow up with employees for missing receipts or documentation&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Prepare monthly expense reporting&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;&lt;span style=&quot;font-size: 12pt;&quot;&gt;Accounts Receivable&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
